import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Helper function to get weather emoji based on condition
  const getWeatherEmoji = (condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
    if (lowerCondition.includes('cloudy') || lowerCondition.includes('overcast')) return '☁️';
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('snowy') || lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('stormy') || lowerCondition.includes('thunder')) return '⛈️';
    if (lowerCondition.includes('windy')) return '💨';
    if (lowerCondition.includes('foggy') || lowerCondition.includes('fog')) return '🌫️';
    return '🌤️';
  };

  const weatherEmoji = getWeatherEmoji(props.condition);

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header with city name */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Weather Forecast</Text>
        </Stack>

        {/* Current Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-6)">
            {/* Temperature and Condition Row */}
            <Row gap="var(--ggui-spacing-4)" align="center">
              {/* Large Temperature Display */}
              <Box paddingY="var(--ggui-spacing-4)">
                <Heading level={1} color="var(--ggui-color-primary-600)" align="center">
                  {props.temperature}°{props.unit}
                </Heading>
              </Box>

              {/* Weather Condition with Icon */}
              <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                <Box>
                  <Icon name={weatherEmoji} size={64} />
                </Box>
                <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)" align="center">
                  {props.condition}
                </Text>
              </Stack>
            </Row>

            <Divider margin="var(--ggui-spacing-4)" />

            {/* Humidity and Wind Speed Row */}
            <Row gap="var(--ggui-spacing-6)" justify="around">
              {/* Humidity Section */}
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-600)" />
                <Stack gap="var(--ggui-spacing-1)" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">
                    {props.humidity}%
                  </Text>
                </Stack>
              </Stack>

              {/* Wind Speed Section */}
              <Stack gap="var(--ggui-spacing-2)" align="center">
                <Icon name="wind" size={24} color="var(--ggui-color-primary-600)" />
                <Stack gap="var(--ggui-spacing-1)" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">
                    {props.windSpeed} km/h
                  </Text>
                </Stack>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast Section */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
            <Row gap="var(--ggui-spacing-2)" wrap justify="between">
              {props.forecast.map((day, index) => (
                <Card
                  key={index}
                  shadow="sm"
                  padding="var(--ggui-spacing-4)"
                  radius="md"
                  border
                  style={{ flex: '1 1 calc(20% - var(--ggui-spacing-2))', minWidth: '100px' }}
                >
                  <Stack gap="var(--ggui-spacing-3)" align="center" justify="center">
                    {/* Day Name */}
                    {day.day && (
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)" weight="semibold">
                        {day.day}
                      </Text>
                    )}

                    {/* Weather Icon */}
                    {day.icon && (
                      <Box>
                        <Icon name={day.icon} size={32} />
                      </Box>
                    )}

                    {/* High/Low Temperatures */}
                    <Stack gap="var(--ggui-spacing-1)" align="center">
                      {day.high !== undefined && (
                        <Text variant="bodySmall" weight="semibold" color="var(--ggui-color-primary-600)">
                          {day.high}°
                        </Text>
                      )}
                      {day.low !== undefined && (
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                          {day.low}°
                        </Text>
                      )}
                    </Stack>
                  </Stack>
                </Card>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

