}





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // State for search and selected element
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<(typeof props.elements)[0] | null>(null);

  // Filter elements by search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el =>
      (el.name?.toLowerCase().includes(query)) ||
      (el.symbol?.toLowerCase().includes(query))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories for legend
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  // Map category to color token
  const categoryColorMap: Record<string, string> = {
    'alkali-metal': 'var(--ggui-color-primary-100)',
    'alkaline-earth-metal': 'var(--ggui-color-primary-50)',
    'transition-metal': 'var(--ggui-color-info-100)',
    'lanthanide': 'var(--ggui-color-warning-100)',
    'actinide': 'var(--ggui-color-error-100)',
    'nonmetal': 'var(--ggui-color-success-100)',
    'halogen': 'var(--ggui-color-error-50)',
    'noble-gas': 'var(--ggui-color-info-50)',
    'metalloid': 'var(--ggui-color-warning-50)',
  };

  const getCategoryColor = (category?: string) => {
    if (!category) return 'var(--ggui-color-surfaceVariant)';
    return categoryColorMap[category] || 'var(--ggui-color-surfaceVariant)';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Title */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Click on an element to view details. {filteredElements.length} of {props.elements.length} elements shown.
          </Text>
        </Stack>

        {/* Search Input */}
        <SearchField
          value={searchQuery}
          onChange={setSearchQuery}
          onSearch={(q) => setSearchQuery(q)}
          placeholder="Search by element name or symbol (e.g., Gold, Au)..."
          size="md"
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Legend</Text>
            <Row gap="var(--ggui-spacing-3)" wrap>
              {categories.map(cat => (
                <Row key={cat} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    background={getCategoryColor(cat)}
                    borderRadius="var(--ggui-shape-radius-sm)"
                    style={{ width: '24px', height: '24px', border: '1px solid var(--ggui-color-outlineVariant)' }}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" style={{ textTransform: 'capitalize' }}>
                    {cat.replace(/-/g, ' ')}
                  </Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2)',
          }}
        >
          {filteredElements.map(element => (
            <Card
              key={element.atomicNumber || element.symbol}
              padding="var(--ggui-spacing-2)"
              shadow="sm"
              as={Clickable}
              onClick={() => setSelectedElement(element)}
              style={{
                background: getCategoryColor(element.category),
                cursor: 'pointer',
                gridColumn: element.col,
                gridRow: element.row,
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'center',
                alignItems: 'center',
                minHeight: '80px',
                transition: 'all 200ms ease-in-out',
              }}
              hoverStyle={{ opacity: 0.8, transform: 'scale(1.05)' }}
            >
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant)"
                style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
              >
                {element.atomicNumber}
              </Text>
              <Text
                variant="overline"
                color="var(--ggui-color-onSurface)"
                size="2xl"
                weight="bold"
                align="center"
              >
                {element.symbol}
              </Text>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant)"
                align="center"
                style={{ fontSize: 'var(--ggui-font-size-xs)' }}
              >
                {element.name}
              </Text>
            </Card>
          ))}
        </Box>

        {/* Detail Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md" border>
            <Stack gap="var(--ggui-spacing-4)">
              <Row justify="between" align="center">
                <Stack gap="var(--ggui-spacing-1)">
                  <Heading level={2}>{selectedElement.name}</Heading>
