                    Atomic Number: {selectedElement.atomicNumber}
                  </Text>
                </Stack>
                <Button
                  variant="ghost"
                  onClick={() => setSelectedElement(null)}
                >
                  Close
                </Button>
              </Row>
              <Divider />
              <Row gap="var(--ggui-spacing-6)" wrap>
                <Stack gap="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Symbol</Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                    {selectedElement.symbol}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                    {selectedElement.atomicWeight?.toFixed(3) || 'N/A'}
                  </Text>
                </Stack>
                <Stack gap="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category</Text>
                  <Badge variant="primary" size="md">
                    {selectedElement.category?.replace(/-/g, ' ') || 'Unknown'}
                  </Badge>
                </Stack>
                <Stack gap="var(--ggui-spacing-3)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Position</Text>
                  <Text variant="body" color="var(--ggui-color-onSurface)" weight="semibold">
                    Row {selectedElement.row}, Col {selectedElement.col}
                  </Text>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}

        {/* Empty State */}
        {filteredElements.length === 0 && (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" border>
            <Stack gap="var(--ggui-spacing-3)" align="center" justify="center" style={{ minHeight: '200px' }}>
              <Icon name="search" size={32} color="var(--ggui-color-onSurfaceVariant)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
                No elements found matching "{searchQuery}". Try searching by element name or symbol.
              </Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

