import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };



export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State
  const [inputValue, setInputValue] = useState<string>('');
  const [allMessages, setAllMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom on new messages
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Handle incoming messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Handle typing indicator from stream
  useEffect(() => {
    if (typing.latest) {
      setTypingUsers((prev) => {
        const updated = new Set(prev);
        if (typing.latest?.active && typing.latest?.sender) {
          updated.add(typing.latest.sender);
        } else if (typing.latest?.sender) {
          updated.delete(typing.latest.sender);
        }
        return updated;
      });
    }
  }, [typing.latest]);

  // Handle sending message
  const handleSendMessage = useCallback(() => {
    if (inputValue.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputValue, timestamp });
      // Add to local messages immediately
      setAllMessages((prev) => [
        ...prev,
        { sender: props.currentUser, text: inputValue, timestamp }
      ]);
      setInputValue('');
    }
  }, [inputValue, sendMessage, props.currentUser]);

  // Handle Enter key in input
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLInputElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    return allMessages.reduce((acc, msg, idx) => {
      const prevMsg = allMessages[idx - 1];
      if (prevMsg?.sender === msg.sender) {
        if (acc.length > 0) {
          acc[acc.length - 1].messages.push(msg);
        }
      } else {
        acc.push({ sender: msg.sender, messages: [msg] });
      }
      return acc;
    }, [] as Array<{ sender?: string; messages: Array<{ sender?: string; text?: string; timestamp?: string }> }>);
  }, [allMessages]);

  // Format timestamp
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      return new Date(timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  const isInputDisabled = inputValue.trim().length === 0;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-4)" radius="lg" border>
        <Stack gap="var(--ggui-spacing-4)" align="stretch">
          {/* Header */}
          <Row align="center" justify="between" gap="var(--ggui-spacing-4)">
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="primary" size="sm">
                {props.participantCount} participants
              </Badge>
            </Stack>
            {typingUsers.size > 0 && (
              <Box paddingX="var(--ggui-spacing-2)" paddingY="var(--ggui-spacing-1)" role="status" aria-live="polite" aria-atomic="true">
                <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
                  <Spinner size={16} color="var(--ggui-color-primary-600)" />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    {Array.from(typingUsers).join(', ')} {typingUsers.size === 1 ? 'is' : 'are'} typing...
                  </Text>
                </Stack>
              </Box>
            )}
          </Row>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Messages area */}
          <Box
            padding="var(--ggui-spacing-4)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
            style={{
              height: '400px',
              overflowY: 'auto',
              display: 'flex',
              flexDirection: 'column',
              gap: 'var(--ggui-spacing-3)',
            }}
          >
            {allMessages.length === 0 ? (
              <Box
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  height: '100%',
                }}
              >
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" align="center">
                  No messages yet. Start the conversation!
                </Text>
              </Box>
            ) : (
              <>
                {groupedMessages.map((group, groupIdx) => {
                  const isCurrentUser = group.sender === props.currentUser;
                  return (
                    <Stack
                      key={groupIdx}
                      gap="var(--ggui-spacing-1)"
                      align={isCurrentUser ? 'end' : 'start'}
                      direction="vertical"
                    >
                      {group.messages.map((msg, msgIdx) => (
                        <Card
                          key={msgIdx}
                          padding="var(--ggui-spacing-3)"
                          shadow="sm"
                          radius="md"
                          border={false}
                          style={{
                            maxWidth: '70%',
                            background: isCurrentUser
                              ? 'var(--ggui-color-primary-600)'
                              : 'var(--ggui-color-surfaceVariant)',
                          }}
                        >
                          <Stack gap="var(--ggui-spacing-1)" align="stretch">
                            <Text
                              variant="body"
                              color={isCurrentUser ? 'white' : 'var(--ggui-color-onSurface)'}
                            >
                              {msg.text}
                            </Text>
                            <Text
                              variant="caption"
                              color={isCurrentUser ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                              align={isCurrentUser ? 'right' : 'left'}
                            >
                              {formatTime(msg.timestamp)}
                            </Text>
                          </Stack>
                        </Card>
                      ))}
                    </Stack>
                  );
                })}
                <div ref={messagesEndRef} />
              </>
            )}
          </Box>

          {/* Input area */}
           <Row align="end" gap="var(--ggui-spacing-2)" justify="between">
             <Box style={{ flex: 1 }}>
               <Input
                 label="Message"
                 placeholder="Type a message..."
                 value={inputValue}
                 onChange={setInputValue}
                 onKeyDown={handleKeyDown}
               />
             </Box>
             <Button
               variant="primary"
               size="md"
               onClick={handleSendMessage}
               disabled={isInputDisabled}
             >
               Send
             </Button>
           </Row>
        </Stack>
      </Card>
    </Container>
  );
}

