  const [email, setEmail] = useState(props.initialProfile.email || '');
  const [avatar, setAvatar] = useState(props.initialProfile.avatar || '');
  const [role, setRole] = useState(props.initialProfile.role || '');
  const [emailNotifications, setEmailNotifications] = useState(props.initialProfile.emailNotifications ?? true);
  const [theme, setTheme] = useState(props.initialProfile.theme || 'light');

  // Validation state
  const [emailError, setEmailError] = useState('');

  // Email validation function
  const validateEmail = useCallback((value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  }, []);

  // Handle email change with validation
  const handleEmailChange = useCallback((value: string) => {
    setEmail(value);
    if (value && !validateEmail(value)) {
      setEmailError('Please enter a valid email address');
    } else {
      setEmailError('');
    }
  }, [validateEmail]);

  // Check if step 1 is valid
  const isStep1Valid = useCallback(() => {
    return name.trim() !== '' && email.trim() !== '' && validateEmail(email) && avatar !== '';
  }, [name, email, avatar, validateEmail]);

  // Check if step 2 is valid
  const isStep2Valid = useCallback(() => {
    return role !== '';
  }, [role]);

  // Handle next button
  const handleNext = useCallback(() => {
    if (currentStep === 1 && isStep1Valid()) {
      setCurrentStep(2);
    } else if (currentStep === 2 && isStep2Valid()) {
      setCurrentStep(3);
    }
  }, [currentStep, isStep1Valid, isStep2Valid]);

  // Handle back button
  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  }, [currentStep]);

  // Handle complete/submit
