      email,
      avatar,
      role,
      emailNotifications,
      theme,
    });
  }, [name, email, avatar, role, emailNotifications, theme, complete]);

  // Calculate progress percentage
  const progressPercent = (currentStep / 3) * 100;

  // Convert role value to display text
  const getRoleLabel = (value: string) => {
    return props.roleOptions.find(opt => opt === value) || value || 'Select a role';
