import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const [step, setStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState({ name: false, email: false, satisfaction: false });

  const emailValid = useMemo(() => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim()), [email]);
  const nameError = touched.name && name.trim().length === 0 ? 'Name is required' : '';
  const emailError = touched.email && email.trim().length === 0 ? 'Email is required' : touched.email && !emailValid ? 'Enter a valid email address' : '';
  const satisfactionError = touched.satisfaction && !satisfaction ? 'Please select a satisfaction rating' : '';

  const satisfactionOptions = useMemo(
    () => (props.satisfactionLabels || []).map((label, index) => ({ value: String(index + 1), label })),
    [props.satisfactionLabels],
  );

  const canNext = useMemo(() => {
    if (step === 1) {
      return name.trim().length > 0 && email.trim().length > 0 && emailValid;
    }
    if (step === 2) {
      return satisfaction.length > 0;
    }
    if (step === 3) {
      return true;
    }
    if (step === 4) {
      return comments.length <= 500;
    }
    return true;
  }, [step, name, email, emailValid, satisfaction, comments]);

  const handleToggleFeature = useCallback((feature: string, checked: boolean) => {
    setFeatures((prev) => {
      if (checked) {
        if (prev.includes(feature)) return prev;
        return [...prev, feature];
      }
      return prev.filter((item) => item !== feature);
    });
  }, []);

  const nextStep = useCallback(() => {
    if (step === 1) {
      setTouched((prev) => ({ ...prev, name: true, email: true }));
      if (!(name.trim().length > 0 && email.trim().length > 0 && emailValid)) return;
    }
    if (step === 2) {
      setTouched((prev) => ({ ...prev, satisfaction: true }));
      if (!satisfaction) return;
    }
    if (step < 5) setStep((prev) => prev + 1);
  }, [step, name, email, emailValid, satisfaction]);

  const backStep = useCallback(() => {
    if (step > 1) setStep((prev) => prev - 1);
  }, [step]);

  const handleSubmit = useCallback(() => {
    const payload: ActionSubmitPayload = {
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction || '0'),
      features,
      comments: comments.trim(),
    };
    submit(payload);
  }, [name, email, satisfaction, features, comments, submit]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
        <form
          onSubmit={(event) => {
            event.preventDefault();
            if (step < 5) {
              nextStep();
              return;
            }
            handleSubmit();
          }}
        >
          <Stack gap="var(--ggui-spacing-5)">
            <Stack gap="var(--ggui-spacing-2)">
              <Row justify="between" align="center">
                <Heading level={3}>Survey</Heading>
                <Badge variant="primary">Step {step} of 5</Badge>
              </Row>
              <Progress value={step} max={5} size="md" aria-label="Survey progress" />
            </Stack>

            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Your information</Heading>
                <Input
                  label="Name"
                  required
                  value={name}
                  onChange={setName}
                  onBlur={() => setTouched((prev) => ({ ...prev, name: true }))}
                  error={nameError}
                  placeholder="Enter your name"
                />
                <Input
                  label="Email"
                  type="email"
                  required
                  value={email}
                  onChange={setEmail}
                  onBlur={() => setTouched((prev) => ({ ...prev, email: true }))}
                  error={emailError}
                  placeholder="you@example.com"
                />
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Satisfaction rating</Heading>
                <RadioGroup
                  label="How satisfied are you?"
                  value={satisfaction}
                  onChange={setSatisfaction}
                  options={satisfactionOptions}
                  error={satisfactionError}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Feature interests</Heading>
                <Text color="var(--ggui-color-onSurfaceVariant)">Select all that apply.</Text>
                <Stack gap="var(--ggui-spacing-2)">
                  {(props.featureOptions || []).length === 0 && (
                    <Alert variant="info">No feature options available.</Alert>
                  )}
                  {(props.featureOptions || []).map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={features.includes(feature)}
                      onChange={(checked) => handleToggleFeature(feature, checked)}
                    />
                  ))}
                </Stack>
              </Stack>
            )}

            {step === 4 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Additional comments</Heading>
                <TextArea
                  label="Comments (optional)"
                  value={comments}
                  onChange={setComments}
                  rows={6}
                  maxLength={500}
                  showCount
                  placeholder="Share any additional feedback"
                />
              </Stack>
            )}

            {step === 5 && (
              <Stack gap="var(--ggui-spacing-3)">
                <Heading level={4}>Review your answers</Heading>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Satisfaction:</Text> {satisfaction ? `${satisfaction} - ${(props.satisfactionLabels || [])[Number(satisfaction) - 1] || ''}` : '-'}</Text>
                    <Text><Text is="span" weight="semibold">Features:</Text> {features.length ? features.join(', ') : 'None selected'}</Text>
                    <Text><Text is="span" weight="semibold">Comments:</Text> {comments.trim() || 'No comments provided'}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-2)" />

            <Row justify="between" align="center">
              <Button variant="outline" disabled={step === 1} onClick={backStep}>
                Back
              </Button>
              {step < 5 ? (
                <Button variant="primary" type="submit" disabled={!canNext}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" type="submit">
                  Submit
                </Button>
              )}
            </Row>
          </Stack>
        </form>
      </Card>
    </Container>

  );
}

