import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = {
  action: 'move' | 'edit' | 'create';
  taskId: string;
  data: {
    column: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    dueDate?: string;
  };
};


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [boardTasks, setBoardTasks] = useState<Array<{ id: string; title: string; priority: 'low' | 'medium' | 'high'; assignee: string; column: string; dueDate?: string }>>([]);
  const [newTaskTitleByColumn, setNewTaskTitleByColumn] = useState<Record<string, string>>({});
  const [newTaskPriorityByColumn, setNewTaskPriorityByColumn] = useState<Record<string, 'low' | 'medium' | 'high'>>({});
  const [showAddByColumn, setShowAddByColumn] = useState<Record<string, boolean>>({});
  const [editingTaskId, setEditingTaskId] = useState<string>('');
  const [editingTitle, setEditingTitle] = useState<string>('');
  const [updateError, setUpdateError] = useState<string>('');
  const [streamError, setStreamError] = useState<string>('');
  useEffect(() => {
    const normalized = (props.tasks || []).map((task, index) => ({
      id: task.id || `task-${index + 1}` ,
      title: task.title || 'Untitled task',
      priority: task.priority || 'low',
      assignee: task.assignee || 'NA',
      column: task.column || 'todo',
      dueDate: task.dueDate,
    }));
    setBoardTasks(normalized);
  }, [props.tasks]);

  useEffect(() => {
    if (!taskChanged.latest) return;
    if (!taskChanged.latest.task || !taskChanged.latest.task.id) {
      setStreamError('Received an unsupported live update. Please refresh if board looks out of sync.');
      return;
    }
    setStreamError('');
    const incoming = taskChanged.latest.task;
    const incomingId = incoming.id;
    const normalizedIncoming = {
      id: incomingId,
      title: incoming.title || 'Untitled task',
      priority: incoming.priority || 'low' as 'low' | 'medium' | 'high',
      assignee: incoming.assignee || 'NA',
      column: incoming.column || 'todo',
      dueDate: incoming.dueDate,
    };

    setBoardTasks((prev) => {
      if (taskChanged.latest?.action === 'delete') {
        return prev.filter((t) => t.id !== incomingId);
      }
      const exists = prev.some((t) => t.id === incomingId);
      if (!exists) return [...prev, normalizedIncoming];
      return prev.map((t) => (t.id === incomingId ? { ...t, ...normalizedIncoming } : t));
    });
  }, [taskChanged.latest]);

  const columns = useMemo(() => {
    return (props.columns || []).map((column, index) => ({
      id: column.id || `column-${index + 1}`,
      name: column.name || `Column ${index + 1}`,
    }));
  }, [props.columns]);

  const priorityVariant = useCallback((priority: 'low' | 'medium' | 'high'): 'success' | 'warning' | 'error' => {
    if (priority === 'high') return 'error';
    if (priority === 'medium') return 'warning';
    return 'success';
  }, []);

  const totalTasks = boardTasks.length;
  const doneColumnId = columns.find((c) => (c.name || '').toLowerCase() === 'done')?.id || 'done';
  const completedCount = boardTasks.filter((task) => task.column === doneColumnId || task.column === 'done').length;

  const moveTask = useCallback((taskId: string, targetColumnId: string) => {
    const currentTask = boardTasks.find((task) => task.id === taskId);
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: targetColumnId } : task)));
    try {
      taskUpdate({ action: 'move', taskId, data: { column: targetColumnId } });
      setUpdateError('');
    } catch (error) {
      setUpdateError('Could not move task. Please try again.');
      setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? { ...task, column: currentTask?.column || task.column } : task)));
    }
  }, [taskUpdate, boardTasks]);

  const saveTaskTitle = useCallback((taskId: string) => {
    const trimmed = editingTitle.trim();
    if (!trimmed) return;
    const currentTask = boardTasks.find((task) => task.id === taskId);
    if (!currentTask) return;
    const updatedTask = { ...currentTask, title: trimmed };
    setBoardTasks((prev) => prev.map((task) => (task.id === taskId ? updatedTask : task)));
    setEditingTaskId('');
    setEditingTitle('');
    try {
      taskUpdate({ action: 'edit', taskId, data: { column: updatedTask.column, title: updatedTask.title, priority: updatedTask.priority, assignee: updatedTask.assignee, dueDate: updatedTask.dueDate || '' } });
      setUpdateError('');
    } catch (error) {
      setUpdateError('Could not save task title. Please retry.');
    }
  }, [editingTitle, boardTasks, taskUpdate]);

  const createTask = useCallback((columnId: string) => {
    const title = (newTaskTitleByColumn[columnId] || '').trim();
    const priority = newTaskPriorityByColumn[columnId] || 'low';
    if (!title) return;
    const todoColumnId = columns.find((c) => (c.name || '').toLowerCase() === 'to do')?.id || 'todo';
    const newId = `task-${Date.now()}`;
    const newTask = { id: newId, title, priority, assignee: 'NA', column: todoColumnId };
    setBoardTasks((prev) => [...prev, newTask]);
    setNewTaskTitleByColumn((prev) => ({ ...prev, [columnId]: '' }));
    setNewTaskPriorityByColumn((prev) => ({ ...prev, [columnId]: 'low' }));
    setShowAddByColumn((prev) => ({ ...prev, [columnId]: false }));
    try {
      taskUpdate({ action: 'create', taskId: newId, data: { column: newTask.column, title: newTask.title, priority: newTask.priority, assignee: newTask.assignee, dueDate: '' } });
      setUpdateError('');
    } catch (error) {
      setUpdateError('Could not create task. Please try again.');
    }
  }, [newTaskTitleByColumn, newTaskPriorityByColumn, columns, taskUpdate]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border>
          <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
            <Heading level={1}>Task Board</Heading>
            <Row gap="var(--ggui-spacing-3)">
              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
            </Row>
          </Row>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Live updates received: {taskChanged.all.length}
          </Text>
        </Card>
        {updateError && (
          <Alert variant="error" title="Update failed">
            {updateError}
          </Alert>
        )}

        {streamError && (
          <Alert variant="warning" title="Live update issue">
            {streamError}
          </Alert>
        )}
        {columns.length === 0 && (
          <Alert variant="warning" title="No columns configured">
            Please provide columns in props.columns to render the Kanban board.
          </Alert>
        )}

        <Row gap="var(--ggui-spacing-4)" align="start" wrap>
          {columns.map((column) => {
            const tasksInColumn = boardTasks.filter((task) => task.column === column.id);
            return (
              <Card
                key={column.id}
                padding="var(--ggui-spacing-4)"
                shadow="sm"
                border
              >
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between" align="center">
                    <Heading level={2}>{column.name}</Heading>
                    <Badge variant="default">{tasksInColumn.length}</Badge>
                  </Row>

                  {tasksInColumn.length === 0 && (
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      No tasks in this column.
                    </Text>
                  )}

                  <Stack gap="var(--ggui-spacing-3)">
                    {tasksInColumn.map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3)" shadow="none" border>
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="center" gap="var(--ggui-spacing-2)">
                            {editingTaskId === task.id ? (
                              <Input
                                label="Edit task title"
                                value={editingTitle}
                                onChange={setEditingTitle}
                                placeholder="Task title"
                              />
                            ) : (
                              <Text
                                as={Clickable}
                                is="span"
                                variant="label"
                                color="var(--ggui-color-onSurface)"
                                onClick={() => {
                                  setEditingTaskId(task.id);
                                  setEditingTitle(task.title);
                                }}
                                onDoubleClick={() => {
                                  setEditingTaskId(task.id);
                                  setEditingTitle(task.title);
                                }}
                                title="Double-click to edit. Keyboard: focus and press Enter."
                                aria-label={`Task title ${task.title}. Double-click to edit, or press Enter when focused.`}
                              >
                                {task.title}
                              </Text>
                            )}
                            <Badge variant={priorityVariant(task.priority)}>{task.priority}</Badge>
                          </Row>

                          <Row justify="between" align="center">
                            <Row align="center" gap="var(--ggui-spacing-2)">
                              <Avatar name={task.assignee} size="sm" />
                              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                {task.assignee}
                              </Text>
                            </Row>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                              {task.dueDate ? `Due: ${task.dueDate}` : 'No due date'}
                            </Text>
                          </Row>

                          <Select
                            label="Move task"
                            value={task.column}
                            onChange={(value) => moveTask(task.id, value)}
                            options={columns.map((c) => ({ value: c.id, label: c.name }))}
                          />

                          <Row gap="var(--ggui-spacing-2)">
                            {editingTaskId === task.id ? (
                              <>
                                <Button size="sm" onPress={() => saveTaskTitle(task.id)}>Save</Button>
                                <Button
                                  size="sm"
                                  variant="ghost"
                                  onPress={() => {
                                    setEditingTaskId('');
                                    setEditingTitle('');
                                  }}
                                >
                                  Cancel
                                </Button>
                              </>
                            ) : (
                              <Button
                                size="sm"
                                variant="outline"
                                onPress={() => {
                                  setEditingTaskId(task.id);
                                  setEditingTitle(task.title);
                                }}
                              >
                                Edit
                              </Button>
                            )}
                          </Row>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {showAddByColumn[column.id] ? (
                    <Card padding="var(--ggui-spacing-3)" border shadow="none">
                      <Stack gap="var(--ggui-spacing-2)">
                        <Input
                          label="Task title"
                          value={newTaskTitleByColumn[column.id] || ''}
                          onChange={(value) => setNewTaskTitleByColumn((prev) => ({ ...prev, [column.id]: value }))}
                          placeholder="Enter task title"
                        />
                        <Select
                          label="Priority"
                          value={newTaskPriorityByColumn[column.id] || 'low'}
                          onChange={(value) => setNewTaskPriorityByColumn((prev) => ({ ...prev, [column.id]: (value as 'low' | 'medium' | 'high') }))}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' },
                          ]}
                        />
                        <Row gap="var(--ggui-spacing-2)">
                          <Button size="sm" onPress={() => createTask(column.id)}>Create</Button>
                          <Button size="sm" variant="ghost" onPress={() => setShowAddByColumn((prev) => ({ ...prev, [column.id]: false }))}>Cancel</Button>
                        </Row>
                      </Stack>
                    </Card>
                  ) : (
                    <Button variant="secondary" onPress={() => setShowAddByColumn((prev) => ({ ...prev, [column.id]: true }))}>
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Card>
            );
          })}
        </Row>
      </Stack>
    </Container>

  );
}

