import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}


const getCategoryColor = (category?: string): string => {
  const normalizedKey = (category || 'unknown').toLowerCase().replace(/-/g, ' ').trim();
  const map: Record<string, string> = {
    'alkali metal': 'var(--ggui-color-error-100)',
    'alkaline earth metal': 'var(--ggui-color-warning-100)',
    'transition metal': 'var(--ggui-color-primary-100)',
    'post-transition metal': 'var(--ggui-color-info-100)',
    metalloid: 'var(--ggui-color-success-100)',
    nonmetal: 'var(--ggui-color-surfaceVariant)',
    halogen: 'var(--ggui-color-warning-100)',
    'noble gas': 'var(--ggui-color-primary-200)',
    lanthanide: 'var(--ggui-color-success-100)',
    actinide: 'var(--ggui-color-error-100)',
    unknown: 'var(--ggui-color-outlineVariant)',
  };
  return map[normalizedKey] || 'var(--ggui-color-outlineVariant)';
};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const [query, setQuery] = useState<string>('');
  const [selectedAtomicNumber, setSelectedAtomicNumber] = useState<number | null>(null);

  const safeElements = useMemo(() => props.elements || [], [props.elements]);

  const filteredAtomicNumbers = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return new Set(safeElements.map((el) => el.atomicNumber).filter((n): n is number => typeof n === 'number'));
    return new Set(
      safeElements
        .filter((el) => {
          const name = (el.name || '').toLowerCase();
          const symbol = (el.symbol || '').toLowerCase();
          return name.includes(q) || symbol.includes(q);
        })
        .map((el) => el.atomicNumber)
        .filter((n): n is number => typeof n === 'number')
    );
  }, [safeElements, query]);

  const categories = useMemo(() => {
    const unique = new Set<string>();
    safeElements.forEach((el) => {
      unique.add(el.category || 'unknown');
    });
    return Array.from(unique).sort((a, b) => a.localeCompare(b));
  }, [safeElements]);

  const selectedElement = useMemo(() => {
    if (selectedAtomicNumber === null) return null;
    return safeElements.find((el) => el.atomicNumber === selectedAtomicNumber) || null;
  }, [safeElements, selectedAtomicNumber]);

  useEffect(() => {
    if (selectedAtomicNumber === null) return;
    const exists = safeElements.some((el) => el.atomicNumber === selectedAtomicNumber);
    if (!exists) setSelectedAtomicNumber(null);
  }, [safeElements, selectedAtomicNumber]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Interactive Periodic Table</Heading>
          <Text color="var(--ggui-color-onSurfaceVariant)">
            Explore elements by category, search by name or symbol, and select an element for details.
          </Text>
        </Stack>

        <Input
          label="Search elements"
          placeholder="Type element name or symbol (e.g., Oxygen, O)"
          value={query}
          onChange={setQuery}
        />

        {safeElements.length === 0 ? (
          <Alert variant="warning" title="No element data">
            No elements were provided in props.elements.
          </Alert>
        ) : (
          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Box
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(18, minmax(0, 1fr))',
                gap: 'var(--ggui-spacing-2)',
                overflowX: 'auto',
                alignItems: 'stretch',
              }}
            >
              {safeElements.map((el, index) => {
                const atomicNumber = el.atomicNumber || 0;
                const isMatch = filteredAtomicNumbers.has(atomicNumber);
                const isSelected = selectedAtomicNumber === atomicNumber;
                return (
                  <Card
                    key={`${atomicNumber}-${el.symbol || index}`}
                    as={Clickable}
                    onClick={() => setSelectedAtomicNumber(atomicNumber)}
                    onKeyDown={(event: React.KeyboardEvent) => {
                      if (event.key === 'Enter' || event.key === ' ') {
                        event.preventDefault();
                        setSelectedAtomicNumber(atomicNumber);
                      }
                    }}
                    aria-label={`${el.name || 'Unknown element'} (${el.symbol || '—'}), atomic number ${el.atomicNumber || 'unknown'}`}
                    padding="var(--ggui-spacing-2)"
                    radius="md"
                    border
                    shadow="none"
                    hoverStyle={{ opacity: 0.9 }}
                    style={{
                      gridColumn: `${el.col || 1}` ,
                      gridRow: `${el.row || 1}` ,
                      minHeight: 'var(--ggui-spacing-12)',
                      position: 'relative',
                      background: isMatch ? getCategoryColor(el.category) : 'var(--ggui-color-surface)',
                      border: isSelected
                        ? '2px solid var(--ggui-color-primary-600)'
                        : '1px solid var(--ggui-color-outline)',
                      opacity: isMatch ? 1 : 0.35,
                      outline: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                      outlineOffset: '2px',
                    }}
                  >
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurfaceVariant)"
                      style={{ position: 'absolute', top: 'var(--ggui-spacing-1)', left: 'var(--ggui-spacing-1)' }}
                    >
                      {el.atomicNumber || '—'}
                    </Text>
                    <Stack align="center" justify="center" style={{ height: '100%' }}>
                      <Text size="xl" weight="bold" align="center">
                        {el.symbol || '—'}
                      </Text>
                    </Stack>
                  </Card>
                );
              })}
            </Box>
          </Box>
        )}

        <Card padding="var(--ggui-spacing-4)" border radius="lg">
          <Stack gap="var(--ggui-spacing-2)">
            <Heading level={3}>Selected Element Details</Heading>
            {selectedElement ? (
              <Stack gap="var(--ggui-spacing-1)">
                <Text><Text is="span" weight="semibold">Name:</Text> {selectedElement.name || '—'}</Text>
                <Text><Text is="span" weight="semibold">Symbol:</Text> {selectedElement.symbol || '—'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Number:</Text> {selectedElement.atomicNumber || '—'}</Text>
                <Text><Text is="span" weight="semibold">Atomic Weight:</Text> {selectedElement.atomicWeight || '—'}</Text>
                <Text><Text is="span" weight="semibold">Category:</Text> {selectedElement.category || '—'}</Text>
              </Stack>
            ) : (
              <Text color="var(--ggui-color-onSurfaceVariant)">
                Click an element cell to view details.
              </Text>
            )}
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4)" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3}>Legend</Heading>
            <Row wrap gap="var(--ggui-spacing-2)">
              {categories.map((category) => (
                <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                  <Box
                    style={{
                      width: 'var(--ggui-spacing-3)',
                      height: 'var(--ggui-spacing-3)',
                      borderRadius: 'var(--ggui-shape-radius-sm)',
                      background: getCategoryColor(category),
                      border: '1px solid var(--ggui-color-outline)',
                    }}
                  />
                  <Text variant="bodySmall">{category}</Text>
                </Row>
              ))}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

