type ActionAddToCartPayload = { productId: string; quantity: number };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }
  const [activeTab, setActiveTab] = useState('description');
  const [quantity, setQuantity] = useState(1);

  const maxStock = useMemo(() => {
    if (typeof props.product?.stock !== 'number' || props.product.stock < 0) return 0;
    return Math.floor(props.product.stock);
  }, [props.product?.stock]);

  useEffect(() => {
    if (maxStock <= 0) {
      setQuantity(1);
      return;
    }
    setQuantity((prev) => {
      if (prev < 1) return 1;
      if (prev > maxStock) return maxStock;
      return prev;
    });
  }, [maxStock]);

  const formattedPrice = useMemo(() => {
    const priceValue = typeof props.product?.price === 'number' ? props.product.price : 0;
    const currencyValue = props.product?.currency || '$';
    return `${currencyValue}${priceValue.toFixed(2)}`;
  }, [props.product?.price, props.product?.currency]);

  const normalizedRating = useMemo(() => {
    const ratingValue = typeof props.product?.rating === 'number' ? props.product.rating : 0;
    return Math.max(0, Math.min(5, Math.round(ratingValue)));
  }, [props.product?.rating]);

  const specificationRows = useMemo(() => {
    if (!Array.isArray(props.product?.specifications)) return [];
    return props.product.specifications
      .map((spec, index) => {
        if (!spec || typeof spec !== 'object') return null;
        const keyValue = (spec as { key?: unknown; name?: unknown; label?: unknown }).key ?? (spec as { key?: unknown; name?: unknown; label?: unknown }).name ?? (spec as { key?: unknown; name?: unknown; label?: unknown }).label;
        const valueValue = (spec as { value?: unknown }).value;
        return {
          id: `${String(keyValue ?? 'spec')}-${index}`,
          key: String(keyValue ?? `Specification ${index + 1}`),
          value: String(valueValue ?? '-'),
        };
      })
      .filter((item): item is { id: string; key: string; value: string } => item !== null);
  }, [props.product?.specifications]);

  const reviewRows = useMemo(() => {
    if (!Array.isArray(props.product?.reviews)) return [];
    return props.product.reviews
      .map((review, index) => {
        if (!review || typeof review !== 'object') return null;
        const reviewObject = review as { author?: unknown; rating?: unknown; text?: unknown; date?: unknown };
        const ratingValue = typeof reviewObject.rating === 'number' ? Math.max(0, Math.min(5, Math.round(reviewObject.rating))) : 0;
        return {
          id: `review-${index}`,
          author: String(reviewObject.author ?? 'Anonymous'),
          rating: ratingValue,
          text: String(reviewObject.text ?? ''),
          date: String(reviewObject.date ?? ''),
        };
      })
      .filter((item): item is { id: string; author: string; rating: number; text: string; date: string } => item !== null);
  }, [props.product?.reviews]);

  const isOutOfStock = maxStock <= 0;

  const handleDecrease = useCallback(() => {
    setQuantity((prev) => Math.max(1, prev - 1));
  }, []);

  const handleIncrease = useCallback(() => {
    if (maxStock <= 0) return;
    setQuantity((prev) => Math.min(maxStock, prev + 1));
  }, [maxStock]);

  const handleAddToCart = useCallback(() => {
    if (!props.product?.id || isOutOfStock) return;
    addToCart({
      productId: props.product.id,
      quantity,
    });
  }, [addToCart, props.product?.id, quantity, isOutOfStock]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Row wrap gap="var(--ggui-spacing-6)">
          <Card
            padding="var(--ggui-spacing-6)"
            radius="lg"
            shadow="sm"
            border
          >
            <Box
              background="var(--ggui-color-primary-50)"
              borderRadius="var(--ggui-shape-radius-lg)"
              padding="var(--ggui-spacing-12)"
            >
              <Stack align="center" justify="center" gap="var(--ggui-spacing-2)">
                <Icon name="image" color="var(--ggui-color-primary-600)" size={40} />
                <Text
                  variant="label"
                  color="var(--ggui-color-primary-700)"
                  align="center"
                >
                  {props.product?.name || 'Unnamed Product'}
                </Text>
              </Stack>
            </Box>
          </Card>

          <Stack gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                {props.product?.name || 'Unnamed Product'}
              </Heading>
              <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-primary-700)">
                {formattedPrice}
              </Text>
              <Row gap="var(--ggui-spacing-2)" align="center" wrap>
                <Row gap="var(--ggui-spacing-1)" aria-label={`Rated ${String(normalizedRating)} out of 5`}>
                  {[1, 2, 3, 4, 5].map((star) => (
                    <Icon
                      key={`star-${star}`}
                      name={star <= normalizedRating ? 'star' : 'star-off'}
                      color={star <= normalizedRating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                      size={18}
                    />
                  ))}
                </Row>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                  ({String(props.product?.reviewCount ?? reviewRows.length)} reviews)
                </Text>
              </Row>
              <Badge variant={maxStock > 5 ? 'success' : maxStock > 0 ? 'warning' : 'error'} size="md">
                {maxStock > 5 ? 'In Stock' : maxStock > 0 ? 'Low Stock' : 'Out of Stock'}
              </Badge>
            </Stack>
          </Stack>
        </Row>

        <Card padding="var(--ggui-spacing-4)" border radius="lg" shadow="sm">
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            variant="line"
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="body" color="var(--ggui-color-onSurface)">
                      {props.product?.description || 'No description available.'}
                    </Text>
                  </Stack>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: specificationRows.length > 0 ? (
                  <Table
                    columns={[
                      { key: 'key', header: 'Specification' },
                      { key: 'value', header: 'Value' },
                    ]}
                    data={specificationRows}
                    bordered
                    striped
                  />
                ) : (
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    No specifications available.
                  </Text>
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: reviewRows.length > 0 ? (
                  <Stack gap="var(--ggui-spacing-4)">
                    {reviewRows.map((review) => (
                      <Card key={review.id} padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Row justify="between" align="center" wrap>
                            <Text variant="label" color="var(--ggui-color-onSurface)">
                              {review.author}
                            </Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                              {review.date}
                            </Text>
                          </Row>
                          <Row gap="var(--ggui-spacing-1)" aria-label={`Rated ${String(review.rating)} out of 5`}>
                            {[1, 2, 3, 4, 5].map((star) => (
                              <Icon
                                key={`${review.id}-star-${star}`}
                                name={star <= review.rating ? 'star' : 'star-off'}
                                color={star <= review.rating ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outline)'}
                                size={16}
                              />
                            ))}
                          </Row>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
                            {review.text}
                          </Text>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>
                ) : (
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    No reviews yet.
                  </Text>
                ),
              },
            ]}
          />
        </Card>

        <Card padding="var(--ggui-spacing-4)" border radius="lg" shadow="sm">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={4}>Purchase</Heading>
            <Row gap="var(--ggui-spacing-3)" align="center" wrap>
              <Text variant="label" color="var(--ggui-color-onSurface)">
                Quantity
              </Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onPress={handleDecrease}
                  disabled={isOutOfStock || quantity <= 1}
                  aria-label="Decrease quantity"
                >
                  −
                </Button>
                <Input
                  label="Quantity"
                  type="number"
                  value={String(quantity)}
                  onChange={(value) => {
                    const parsed = Number(value);
                    if (Number.isNaN(parsed)) return;
                    const clampedMax = maxStock > 0 ? maxStock : 1;
                    const clamped = Math.max(1, Math.min(clampedMax, Math.floor(parsed)));
                    setQuantity(clamped);
                  }}
                  disabled={isOutOfStock}
                />
                <Button
                  variant="outline"
                  size="sm"
                  onPress={handleIncrease}
                  disabled={isOutOfStock || quantity >= maxStock}
                  aria-label="Increase quantity"
                >
                  +
                </Button>
              </Row>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Max: {String(maxStock)}
              </Text>
            </Row>
            <Button
              variant="primary"
              disabled={isOutOfStock || !props.product?.id}
              onPress={handleAddToCart}
            >
              {isOutOfStock ? 'Out of Stock' : 'Add to Cart'}
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>

  );
}

