interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag
  const [chatMessages, setChatMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages || []);
  const [draftMessage, setDraftMessage] = useState<string>('');
  const [typingUser, setTypingUser] = useState<string>('');
  const messagesEndRef = useRef<HTMLDivElement | null>(null);

  useEffect(() => {
    setChatMessages(props.messages || []);
  }, [props.messages]);

  useEffect(() => {
    if (message.latest) {
      setChatMessages((prev) => [...prev, message.latest as StreamMessage]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (!typing.latest) {
      return;
    }
    if (typing.latest.active && typing.latest.sender && typing.latest.sender !== props.currentUser) {
      setTypingUser(typing.latest.sender);
    } else {
      setTypingUser('');
    }
  }, [typing.latest, props.currentUser]);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, typingUser]);

  const groupedMessages = useMemo(() => {
    const groups: Array<{ sender?: string; items: Array<{ sender?: string; text?: string; timestamp?: string }> }> = [];
    (chatMessages || []).forEach((item) => {
      const previous = groups[groups.length - 1];
      if (previous && previous.sender === item.sender) {
        previous.items.push(item);
      } else {
        groups.push({ sender: item.sender, items: [item] });
      }
    });
    return groups;
  }, [chatMessages]);

  const formatTimestamp = useCallback((value?: string) => {
    if (!value) {
      return '';
    }
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) {
      return value;
    }
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  }, []);

  const handleSend = useCallback(() => {
    const trimmed = draftMessage.trim();
    if (!trimmed) {
      return;
    }
    const timestamp = new Date().toISOString();
    sendMessage({ text: trimmed, timestamp });
    setChatMessages((prev) => [...prev, { sender: props.currentUser, text: trimmed, timestamp }]);
    setDraftMessage('');
  }, [draftMessage, sendMessage, props.currentUser]);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-4)" shadow="sm" radius="lg">
        <Stack gap="var(--ggui-spacing-4)">
