            <Row gap="var(--ggui-spacing-2)" align="center">
              <Badge variant="primary">{props.participantCount} participants</Badge>
              {typingUser ? (
                <Badge variant="default">{typingUser} is typing...</Badge>
              ) : null}
            </Row>
          </Row>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack gap="var(--ggui-spacing-3)">
              <Box
                style={{
                  maxHeight: '60vh',
                  overflowY: 'auto',
                  paddingRight: 'var(--ggui-spacing-1)',
                }}
              >
                <Stack gap="var(--ggui-spacing-3)">
                  {groupedMessages.length === 0 ? (
                    <Text color="var(--ggui-color-onSurfaceVariant)">No messages yet.</Text>
                  ) : (
                    groupedMessages.map((group, groupIndex) => {
                      const isOwn = group.sender === props.currentUser;
                      return (
                        <Stack
                          key={`${group.sender || 'unknown'}-${groupIndex}`}
                          align={isOwn ? 'end' : 'start'}
                          gap="var(--ggui-spacing-2)"
                        >
                          {group.items.map((msg, messageIndex) => (
                            <Box
                              key={`${groupIndex}-${messageIndex}-${msg.timestamp || 't'}` }
                              padding="var(--ggui-spacing-3)"
                              background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                              borderRadius="var(--ggui-shape-radius-md)"
                              style={{ maxWidth: '75%' }}
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text
                                  variant="label"
                                  color={isOwn ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                >
                                  {msg.sender || 'Unknown'}
                                </Text>
                                <Text
                                  color={isOwn ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                >
                                  {msg.text || ''}
                                </Text>
                                <Text
                                  variant="caption"
                                  color={isOwn ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                  align={isOwn ? 'right' : 'left'}
                                >
                                  {formatTimestamp(msg.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          ))}
                        </Stack>
                      );
                    })
                  )}
                  <Box><div ref={messagesEndRef} /></Box>
                </Stack>
              </Box>

              <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

              <Row gap="var(--ggui-spacing-2)" align="end">
                <Box style={{ flex: 1 }}>
                  <Input
                    label="Message"
                    placeholder="Type your message"
                    value={draftMessage}
                    onChange={setDraftMessage}
                    onKeyDown={(event) => {
                      if (event.key === 'Enter') {
                        event.preventDefault();
                        handleSend();
                      }
                    }}
                  />
                </Box>
                <Button
                  as={Clickable}
                  onClick={handleSend}
                  variant="primary"
                  disabled={!draftMessage.trim()}
                >
                  Send
                </Button>
              </Row>
            </Stack>
          </Box>
        </Stack>
      </Card>
    </Container>

  );
}

