interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update
  const [stocksState, setStocksState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdatedMs, setLastUpdatedMs] = useState<number>(() => {
    const initialTs = marketStatus.latest?.timestamp ? Date.parse(marketStatus.latest.timestamp) : NaN;
    return Number.isNaN(initialTs) ? Date.now() : initialTs;
  });
  const [nowMs, setNowMs] = useState<number>(Date.now());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setStocksState(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setNowMs(Date.now());
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }
    setStocksState((prev) => {
      const previousList = prev ?? [];
      const index = previousList.findIndex((stock) => stock.symbol === priceUpdate.latest?.symbol);
      const nextStock = {
        ...(index >= 0 ? previousList[index] : {}),
        symbol: priceUpdate.latest?.symbol,
        price: priceUpdate.latest?.price,
        change: priceUpdate.latest?.change,
        changePercent: priceUpdate.latest?.changePercent,
      };
      if (index >= 0) {
        return previousList.map((stock, i) => (i === index ? nextStock : stock));
      }
      return [...previousList, nextStock];
    });
    if (marketStatus.latest?.timestamp) {
      const parsedTs = Date.parse(marketStatus.latest.timestamp);
      if (!Number.isNaN(parsedTs)) {
        setLastUpdatedMs(parsedTs);
      }
    }
    setFlashMap((prev) => ({ ...prev, [priceUpdate.latest?.symbol ?? '']: Date.now() }));
  }, [priceUpdate.latest]);

  const marketStatusLabel = useMemo(() => {
    if (!marketStatus.latest?.status) {
      return 'Unknown';
    }
    return marketStatus.latest.status;
  }, [marketStatus.latest]);

  useEffect(() => {
    if (!marketStatus.latest?.timestamp) {
      return;
    }
    const parsedTs = Date.parse(marketStatus.latest.timestamp);
    if (!Number.isNaN(parsedTs)) {
      setLastUpdatedMs(parsedTs);
    }
  }, [marketStatus.latest]);

  const secondsSinceUpdate = Math.max(0, Math.floor((nowMs - lastUpdatedMs) / 1000));
  const stocksToRender = stocksState ?? [];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" border shadow="sm" radius="lg">
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {secondsSinceUpdate === 0 ? 'just now' : `${secondsSinceUpdate}s ago`}
              </Text>
            </Stack>
            <Badge variant={marketStatusLabel === 'open' ? 'success' : marketStatusLabel === 'closed' ? 'error' : 'warning'}>
              {marketStatusLabel}
            </Badge>
          </Row>
        </Card>

        {stocksToRender.length === 0 ? (
          <Alert variant="info" title="No stocks available">
            Waiting for stock data...
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, lg: 3 }} gap={16}>
            {stocksToRender.map((stock, index) => {
              const isPositive = (stock.change ?? 0) >= 0;
              const borderColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
              const textColor = isPositive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
              const symbolKey = stock.symbol ?? `stock-${index}`;
              const flashAt = flashMap[symbolKey] ?? 0;
              const shouldFlash = Date.now() - flashAt < 1200;
              return (
                <Card
                  key={symbolKey}
                  padding="var(--ggui-spacing-4)"
                  border
                  shadow="sm"
                  radius="lg"
                >
                  <Box
                    background="var(--ggui-color-surface)"
                    borderRadius="var(--ggui-shape-radius-md)"
                    padding="var(--ggui-spacing-2)"
                    borderRadius="var(--ggui-shape-radius-md)"
                  >

                    <Stack gap="var(--ggui-spacing-2)">
                      <Text size="2xl" weight="bold" color="var(--ggui-color-onSurface)">
                        {stock.symbol ?? '—'}
                      </Text>
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name ?? 'Unknown Company'}
                      </Text>
                      <Divider margin="var(--ggui-spacing-1)" />
                      <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                        ${(stock.price ?? 0).toFixed(2)}
                      </Text>
                      <Row justify="between" align="center">
                        <Text variant="bodySmall" color={textColor}>
                          {(stock.change ?? 0) >= 0 ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                        </Text>
                        <Row gap="var(--ggui-spacing-1)" align="center">
                          <Text variant="bodySmall" color={textColor} aria-hidden="true">
                            {isPositive ? '▲' : '▼'}
                          </Text>
                          <Text variant="bodySmall" color={textColor}>
                            {(stock.changePercent ?? 0) >= 0 ? '+' : ''}{(stock.changePercent ?? 0).toFixed(2)}% {isPositive ? 'up' : 'down'}
                          </Text>
                        </Row>
                      </Row>
                    </Stack>
                  </Box>
                  <Box
                    margin="var(--ggui-spacing-2) 0 0 0"
                  >
                    <Box
                      padding="var(--ggui-spacing-1)"
                      background="var(--ggui-color-surfaceVariant)"
                      borderRadius="var(--ggui-shape-radius-sm)"
                    >
                      <Text variant="caption" color={borderColor}>
                        {isPositive ? 'Positive movement' : 'Negative movement'}
                      </Text>
                    </Box>
                  </Box>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding
  const [step, setStep] = useState<number>(1);
  const resolvedAvatarOptions = useMemo(() => {
    if (props.avatarOptions && props.avatarOptions.length > 0) {
      return props.avatarOptions.slice(0, 4);
    }
    return ['😀', '🧑‍💻', '🎨', '🚀'];
  }, [props.avatarOptions]);
  const resolvedRoleOptions = useMemo(() => {
    if (props.roleOptions && props.roleOptions.length > 0) {
      return props.roleOptions;
    }
    return ['Developer', 'Designer', 'Manager', 'Other'];
  }, [props.roleOptions]);

  const [name, setName] = useState<string>(props.initialProfile?.name ?? '');
  const [email, setEmail] = useState<string>(props.initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState<string>(props.initialProfile?.avatar ?? (resolvedAvatarOptions[0] ?? '😀'));
  const [role, setRole] = useState<string>(props.initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState<boolean>(props.initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState<string>(props.initialProfile?.theme ?? 'light');
  const [showSubmitted, setShowSubmitted] = useState<boolean>(false);

  useEffect(() => {
    setName(props.initialProfile?.name ?? '');
    setEmail(props.initialProfile?.email ?? '');
    setAvatar(props.initialProfile?.avatar ?? (resolvedAvatarOptions[0] ?? '😀'));
    setRole(props.initialProfile?.role ?? '');
    setEmailNotifications(props.initialProfile?.emailNotifications ?? true);
    setTheme(props.initialProfile?.theme ?? 'light');
  }, [props.initialProfile, resolvedAvatarOptions]);

  const emailIsValid = useMemo(() => {
    const pattern = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return pattern.test(email.trim());
  }, [email]);

  const stepOneValid = useMemo(() => {
    return name.trim().length > 0 && emailIsValid;
  }, [name, emailIsValid]);

  const stepTwoValid = useMemo(() => {
    return role.trim().length > 0 && (theme === 'light' || theme === 'dark');
  }, [role, theme]);

  const canGoNext = useMemo(() => {
    if (step === 1) return stepOneValid;
    if (step === 2) return stepTwoValid;
    return false;
  }, [step, stepOneValid, stepTwoValid]);

  const progressValue = useMemo(() => (step / 3) * 100, [step]);

  const handleNext = useCallback(() => {
    if (step < 3 && canGoNext) {
      setStep(step + 1);
    }
  }, [step, canGoNext]);

  const handleBack = useCallback(() => {
    if (step > 1) {
      setStep(step - 1);
    }
  }, [step]);

  const handleComplete = useCallback(() => {
    if (!stepOneValid || !stepTwoValid) return;
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
    setShowSubmitted(true);
  }, [complete, name, email, avatar, role, emailNotifications, theme, stepOneValid, stepTwoValid]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-6)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            <Row justify="between" align="center">
              <Heading level={3} color="var(--ggui-color-onSurface)">Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              {step === 1 ? 'Set up your profile details.' : step === 2 ? 'Choose your preferences.' : 'Review and confirm your setup.'}
            </Text>
          </Stack>
        </Card>

        {showSubmitted && (
          <Alert variant="success" title="Setup submitted">
            Your onboarding details have been sent successfully.
          </Alert>
        )}

        <Card
          key={step}
          padding="var(--ggui-spacing-6)"
          shadow="md"
          border
          radius="lg"
          style={{
            animation: 'ggui-slideInUp 300ms ease-out',
            background: 'var(--ggui-color-surfaceVariant)',
          }}
        >
          <Stack gap="var(--ggui-spacing-5)">
            {step === 1 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Name"
                  value={name}
                  onChange={setName}
                  required
                  placeholder="Enter your name"
                  error={name.trim().length === 0 ? 'Name is required' : undefined}
                />
                <Input
                  label="Email"
                  type="email"
                  value={email}
                  onChange={setEmail}
                  required
                  placeholder="you@example.com"
                  error={email.trim().length > 0 && !emailIsValid ? 'Enter a valid email address' : undefined}
                />
                <Stack gap="var(--ggui-spacing-2)">
                  <Text variant="label" color="var(--ggui-color-onSurface)">Choose Avatar</Text>
                  <Row gap="var(--ggui-spacing-3)" wrap>
                    {resolvedAvatarOptions.map((emoji) => (
                      <Card
                        key={emoji}
                        as={Clickable}
                        onClick={() => setAvatar(emoji)}
                        padding="var(--ggui-spacing-3)"
                        border
                        radius="md"
                        style={{
                          minWidth: '64px',
                          textAlign: 'center',
                          borderColor: avatar === emoji ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                          background: avatar === emoji ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                        }}
                      >
                        <Text size="2xl" align="center">{emoji}</Text>
                      </Card>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="Role"
                  value={role}
                  onChange={setRole}
                  placeholder="Select your role"
                  options={resolvedRoleOptions.map((option) => ({ value: option, label: option }))}
                  required
                  error={role.trim().length === 0 ? 'Role is required' : undefined}
                />
                <Toggle
                  label="Email notifications"
                  checked={emailNotifications}
                  onChange={setEmailNotifications}
                />
                <Toggle
                  label="Dark theme"
                  checked={theme === 'dark'}
                  onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>Review & Confirm</Heading>
                <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Row align="center" gap="var(--ggui-spacing-3)">
                      <Avatar name={name || 'User'} size="lg" />
                      <Text size="2xl">{avatar}</Text>
                    </Row>
                    <Divider margin="var(--ggui-spacing-2)" />
                    <Text><Text is="span" weight="semibold">Name:</Text> {name || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Email:</Text> {email || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Role:</Text> {role || '-'}</Text>
                    <Text><Text is="span" weight="semibold">Email Notifications:</Text> {emailNotifications ? 'On' : 'Off'}</Text>
                    <Text><Text is="span" weight="semibold">Theme:</Text> {theme}</Text>
                  </Stack>
                </Card>
              </Stack>
            )}

            <Divider margin="var(--ggui-spacing-1)" />
            <Row justify="between" align="center">
              <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
                Back
              </Button>
              <Row gap="var(--ggui-spacing-2)">
                {step < 3 && (
                  <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                    Next
                  </Button>
                )}
                {step === 3 && (
                  <>
                    <Button variant="outline" onClick={handleBack}>Go Back</Button>
                    <Button variant="primary" onClick={handleComplete} disabled={!(stepOneValid && stepTwoValid)}>
                      Complete Setup
                    </Button>
                  </>
                )}
              </Row>
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
